import{_ as r,o as d,c as a,a2 as o}from"./chunks/framework.DGp-bpT-.js";const b=JSON.parse('{"title":"Веб-дашборд","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://srebot.site360.tech/docs/guide/dashboard.md"}],["link",{"rel":"alternate","hreflang":"ru","href":"https://srebot.site360.tech/docs/guide/dashboard.md"}],["link",{"rel":"alternate","hreflang":"en","href":"https://srebot.site360.tech/docs/en/guide/dashboard.md"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://srebot.site360.tech/docs/guide/dashboard.md"}]]},"headers":[],"relativePath":"guide/dashboard.md","filePath":"guide/dashboard.md","lastUpdated":1779959939000}'),e={name:"guide/dashboard.md"};function s(n,t,l,i,h,g){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="веб-дашборд" tabindex="-1">Веб-дашборд <a class="header-anchor" href="#веб-дашборд" aria-label="Permalink to &quot;Веб-дашборд&quot;">​</a></h1><p><a href="https://srebot.site360.tech" target="_blank" rel="noreferrer">Веб-дашборд SREBot</a> — это центр управления платформой. Здесь вы отслеживаете инциденты, управляете AI-агентами, контролируете баланс токенов и настраиваете аккаунт.</p><h2 id="навигация" tabindex="-1">Навигация <a class="header-anchor" href="#навигация" aria-label="Permalink to &quot;Навигация&quot;">​</a></h2><p>Интерфейс дашборда состоит из <strong>бокового меню</strong> (sidebar) и <strong>верхней панели</strong> (navbar).</p><h3 id="боковое-меню" tabindex="-1">Боковое меню <a class="header-anchor" href="#боковое-меню" aria-label="Permalink to &quot;Боковое меню&quot;">​</a></h3><p>В боковом меню находятся ссылки на все разделы дашборда:</p><table tabindex="0"><thead><tr><th>Раздел</th><th>Путь</th><th>Описание</th></tr></thead><tbody><tr><td>Обзор</td><td><code>/dashboard</code></td><td>Статистика использования и последние инциденты</td></tr><tr><td>Инциденты</td><td><code>/dashboard/incidents</code></td><td>Список всех инцидентов с фильтрацией</td></tr><tr><td>Боты</td><td><code>/dashboard/bots</code></td><td>Управление токенами AI-агентов</td></tr><tr><td>Биллинг</td><td><code>/dashboard/billing</code></td><td>Баланс, тарифы, история транзакций</td></tr><tr><td>Настройки</td><td><code>/dashboard/settings</code></td><td>Пароль и профиль организации</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Видимость разделов зависит от роли</p><p>Разделы <strong>Биллинг</strong> и <strong>Команда</strong> отображаются только для пользователей с ролью <strong>Владелец</strong> или <strong>Администратор</strong>. Участники и Наблюдатели видят только Обзор, Инциденты и Настройки.</p></div><h3 id="переключатель-организации" tabindex="-1">Переключатель организаций <a class="header-anchor" href="#переключатель-организации" aria-label="Permalink to &quot;Переключатель организаций&quot;">​</a></h3><p>В верхней панели находится <strong>выпадающий список организаций</strong>. Если вы состоите в нескольких организациях, нажмите на название текущей организации, чтобы переключиться на другую. Все данные дашборда (инциденты, баланс, боты) привязаны к выбранной организации.</p><hr><h2 id="обзор-dashboard" tabindex="-1">Обзор (<code>/dashboard</code>) <a class="header-anchor" href="#обзор-dashboard" aria-label="Permalink to &quot;Обзор (`/dashboard`)&quot;">​</a></h2><p>Главная страница дашборда предоставляет быстрый срез активности вашей организации.</p><h3 id="карточки-статистики" tabindex="-1">Карточки статистики <a class="header-anchor" href="#карточки-статистики" aria-label="Permalink to &quot;Карточки статистики&quot;">​</a></h3><p>В верхней части страницы расположены три карточки с ключевыми метриками использования:</p><table tabindex="0"><thead><tr><th>Карточка</th><th>Описание</th></tr></thead><tbody><tr><td><strong>Всего инцидентов</strong></td><td>Общее количество обработанных инцидентов за всё время</td></tr><tr><td><strong>Промпт-токены</strong></td><td>Количество входных токенов, отправленных в LLM</td></tr><tr><td><strong>Токены генерации</strong></td><td>Количество выходных токенов, сгенерированных LLM</td></tr></tbody></table><p>На каждой карточке отображается <strong>процент тренда за неделю</strong> — зелёная стрелка при росте и красная при снижении — чтобы вы могли оценить динамику потребления.</p><h3 id="последние-инциденты" tabindex="-1">Последние инциденты <a class="header-anchor" href="#последние-инциденты" aria-label="Permalink to &quot;Последние инциденты&quot;">​</a></h3><p>Под карточками находится таблица <strong>5 последних инцидентов</strong> с краткой информацией:</p><table tabindex="0"><thead><tr><th>Столбец</th><th>Описание</th></tr></thead><tbody><tr><td><strong>Алерт</strong></td><td>Название алерта, вызвавшего инцидент</td></tr><tr><td><strong>Бот</strong></td><td>Имя AI-агента, обработавшего инцидент</td></tr><tr><td><strong>Статус</strong></td><td>Цветной индикатор: 🟢 <code>completed</code>, 🟡 <code>analyzing</code>, 🔴 <code>failed</code></td></tr><tr><td><strong>Время</strong></td><td>Дата и время обнаружения</td></tr><tr><td><strong>Критичность</strong></td><td>Уровень серьёзности: <code>high</code>, <code>medium</code>, <code>low</code></td></tr></tbody></table><p>Нажмите на строку инцидента, чтобы перейти к его детальной карточке.</p><hr><h2 id="управление-ботами-dashboard-bots" tabindex="-1">Управление ботами (<code>/dashboard/bots</code>) <a class="header-anchor" href="#управление-ботами-dashboard-bots" aria-label="Permalink to &quot;Управление ботами (`/dashboard/bots`)&quot;">​</a></h2><p>::: new Раздел <strong>Боты</strong> — это новое место для управления токенами AI-агентов вашей организации. Здесь вы создаете, просматриваете и отзываете токены, которые боты используют для подключения к платформе SREBot. :::</p><h3 id="список-токенов" tabindex="-1">Список токенов <a class="header-anchor" href="#список-токенов" aria-label="Permalink to &quot;Список токенов&quot;">​</a></h3><p>На странице отображается таблица всех токенов агентов в организации:</p><table tabindex="0"><thead><tr><th>Столбец</th><th>Описание</th></tr></thead><tbody><tr><td><strong>Имя</strong></td><td>Название бота, указанное при создании токена</td></tr><tr><td><strong>Дата создания</strong></td><td>Когда был сгенерирован токен</td></tr><tr><td><strong>Статус</strong></td><td><code>Активен</code> или <code>Отозван</code></td></tr></tbody></table><h3 id="создание-нового-токена" tabindex="-1">Создание нового токена <a class="header-anchor" href="#создание-нового-токена" aria-label="Permalink to &quot;Создание нового токена&quot;">​</a></h3><ol><li>Нажмите кнопку <strong>«Создать токен»</strong> в правом верхнем углу.</li><li>В модальном окне введите <strong>имя бота</strong> (например, <code>prod-bot-1</code>).</li><li>Нажмите <strong>«Создать»</strong>.</li><li>Система сгенерирует секретный токен и отобразит его в модальном окне.</li></ol><div class="danger custom-block"><p class="custom-block-title">Токен показывается только один раз</p><p>Сразу после создания скопируйте токен и сохраните его в безопасном месте (например, в менеджере секретов). После закрытия модального окна <strong>увидеть токен повторно невозможно</strong>. Если вы потеряете токен, его придется отозвать и создать новый.</p></div><p>Для удобства рядом с токеном расположена кнопка <strong>копирования в буфер обмена</strong>.</p><h3 id="отзыв-токена" tabindex="-1">Отзыв токена <a class="header-anchor" href="#отзыв-токена" aria-label="Permalink to &quot;Отзыв токена&quot;">​</a></h3><p>Чтобы отозвать токен:</p><ol><li>Нажмите на иконку корзины в строке нужного токена.</li><li>В диалоге подтверждения нажмите <strong>«Отозвать»</strong>.</li></ol><p>После отзыва бот немедленно потеряет доступ к платформе. Действие необратимо — если нужно восстановить доступ, создайте новый токен.</p><h3 id="лимит-токенов" tabindex="-1">Лимит токенов <a class="header-anchor" href="#лимит-токенов" aria-label="Permalink to &quot;Лимит токенов&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Максимум 10 токенов</p><p>Каждая организация может иметь не более <strong>10 активных токенов</strong>. При попытке создать одиннадцатый система покажет ошибку. Если вам нужно больше токенов, сначала отзовите неиспользуемые.</p></div><hr><h2 id="список-инцидентов-dashboard-incidents" tabindex="-1">Список инцидентов (<code>/dashboard/incidents</code>) <a class="header-anchor" href="#список-инцидентов-dashboard-incidents" aria-label="Permalink to &quot;Список инцидентов (`/dashboard/incidents`)&quot;">​</a></h2><p>Страница со списком всех инцидентов организации с поддержкой поиска, фильтрации и пагинации.</p><h3 id="фильтры" tabindex="-1">Фильтры <a class="header-anchor" href="#фильтры" aria-label="Permalink to &quot;Фильтры&quot;">​</a></h3><p>Над таблицей расположены элементы управления:</p><table tabindex="0"><thead><tr><th>Фильтр</th><th>Описание</th></tr></thead><tbody><tr><td><strong>Поиск</strong></td><td>Полнотекстовый поиск по названию алерта</td></tr><tr><td><strong>Дата начала</strong></td><td>Фильтр по начальной дате обнаружения</td></tr><tr><td><strong>Дата окончания</strong></td><td>Фильтр по конечной дате обнаружения</td></tr></tbody></table><h3 id="таблица-инцидентов" tabindex="-1">Таблица инцидентов <a class="header-anchor" href="#таблица-инцидентов" aria-label="Permalink to &quot;Таблица инцидентов&quot;">​</a></h3><p>Инциденты отображаются в постраничной таблице (по <strong>20 записей на страницу</strong>) со следующими столбцами:</p><table tabindex="0"><thead><tr><th>Столбец</th><th>Описание</th></tr></thead><tbody><tr><td><strong>Алерт</strong></td><td>Название алерта (например, <code>HighCpuUsage</code>)</td></tr><tr><td><strong>Бот</strong></td><td>Имя агента, обработавшего инцидент</td></tr><tr><td><strong>Статус</strong></td><td>Цветной бейдж: 🟡 <code>analyzing</code>, 🟢 <code>completed</code>, 🔴 <code>failed</code></td></tr><tr><td><strong>Время</strong></td><td>Дата и время обнаружения инцидента</td></tr><tr><td><strong>Критичность</strong></td><td>Уровень серьёзности (<code>high</code> / <code>medium</code> / <code>low</code>)</td></tr><tr><td><strong>Действия</strong></td><td>Кнопка перехода к детальной карточке</td></tr></tbody></table><p>Для навигации между страницами используйте элементы пагинации внизу таблицы.</p><hr><h2 id="детальная-карточка-инцидента-dashboard-incidents-id" tabindex="-1">Детальная карточка инцидента (<code>/dashboard/incidents/:id</code>) <a class="header-anchor" href="#детальная-карточка-инцидента-dashboard-incidents-id" aria-label="Permalink to &quot;Детальная карточка инцидента (`/dashboard/incidents/:id`)&quot;">​</a></h2><p>Страница детального просмотра инцидента — ключевой инструмент для анализа работы AI-агента. Это позволяет проверить корректность суждений бота (hallucination check) и переиспользовать его PromQL-запросы для создания новых дашбордов в Grafana.</p><h3 id="анализ-первопричины-root-cause-analysis" tabindex="-1">Анализ первопричины (Root Cause Analysis) <a class="header-anchor" href="#анализ-первопричины-root-cause-analysis" aria-label="Permalink to &quot;Анализ первопричины (Root Cause Analysis)&quot;">​</a></h3><p>Основной блок страницы содержит <strong>итоговый вывод LLM</strong> об инциденте, отрендеренный в формате Markdown. В этом блоке бот описывает:</p><ul><li>что произошло;</li><li>вероятную причину сбоя;</li><li>рекомендации по устранению.</li></ul><h3 id="уточняющие-вопросы-follow-up-questions" tabindex="-1">Уточняющие вопросы (Follow-up Questions) <a class="header-anchor" href="#уточняющие-вопросы-follow-up-questions" aria-label="Permalink to &quot;Уточняющие вопросы (Follow-up Questions)&quot;">​</a></h3><p>Если к инциденту задавались уточняющие вопросы через чат, они отображаются ниже блока анализа в виде пар <strong>«Вопрос → Ответ»</strong>. Для каждого follow-up показывается:</p><ul><li>текст вопроса пользователя;</li><li>ответ бота;</li><li><strong>детализация токенов</strong> — сколько входных и выходных токенов было затрачено на конкретный ответ.</li></ul><h3 id="шаги-анализа-analysis-steps" tabindex="-1">Шаги анализа (Analysis Steps) <a class="header-anchor" href="#шаги-анализа-analysis-steps" aria-label="Permalink to &quot;Шаги анализа (Analysis Steps)&quot;">​</a></h3><p>Блок с раскрывающимися секциями, показывающий <strong>мыслительный процесс LLM</strong> — какие инструменты и запросы бот использовал при анализе инцидента.</p><p>Каждый шаг содержит:</p><table tabindex="0"><thead><tr><th>Элемент</th><th>Описание</th></tr></thead><tbody><tr><td><strong>Фаза</strong></td><td>Название этапа (например, <code>PromQL Query</code>, <code>Elasticsearch Search</code>)</td></tr><tr><td><strong>Аргументы запроса</strong></td><td>Параметры, переданные в инструмент (например, PromQL-выражение или DSL-запрос)</td></tr><tr><td><strong>Ответ</strong></td><td>Сокращённый payload, который вернул инструмент</td></tr></tbody></table><p>Нажмите на заголовок шага, чтобы развернуть или свернуть детали.</p><div class="tip custom-block"><p class="custom-block-title">Переиспользование запросов</p><p>Если бот выполнил удачный PromQL-запрос, вы можете скопировать его из шагов анализа и использовать для создания дашборда в Grafana или настройки алерт-правил.</p></div><h3 id="боковая-панель-с-метаданными" tabindex="-1">Боковая панель с метаданными <a class="header-anchor" href="#боковая-панель-с-метаданными" aria-label="Permalink to &quot;Боковая панель с метаданными&quot;">​</a></h3><p>Справа от основного контента расположена панель с метаинформацией об инциденте:</p><table tabindex="0"><thead><tr><th>Поле</th><th>Описание</th></tr></thead><tbody><tr><td><strong>Длительность</strong></td><td>Время, затраченное на анализ</td></tr><tr><td><strong>Обнаружен</strong></td><td>Дата и время обнаружения инцидента</td></tr><tr><td><strong>Входные токены</strong></td><td>Количество токенов, отправленных в LLM</td></tr><tr><td><strong>Выходные токены</strong></td><td>Количество токенов, сгенерированных LLM</td></tr><tr><td><strong>Бот</strong></td><td>Имя агента, обработавшего инцидент</td></tr><tr><td><strong>ID инцидента</strong></td><td>Уникальный идентификатор</td></tr><tr><td><strong>Критичность</strong></td><td>Уровень серьёзности (<code>high</code> / <code>medium</code> / <code>low</code>)</td></tr></tbody></table><hr><h2 id="биллинг-и-токены-dashboard-billing" tabindex="-1">Биллинг и токены (<code>/dashboard/billing</code>) <a class="header-anchor" href="#биллинг-и-токены-dashboard-billing" aria-label="Permalink to &quot;Биллинг и токены (`/dashboard/billing`)&quot;">​</a></h2><p>SREBot использует <strong>token-based</strong> систему биллинга для оплаты вызовов LLM. Вся информация о расходах и пополнениях сосредоточена на этой странице.</p><h3 id="текущии-баланс" tabindex="-1">Текущий баланс <a class="header-anchor" href="#текущии-баланс" aria-label="Permalink to &quot;Текущий баланс&quot;">​</a></h3><p>В верхней части страницы отображается <strong>текущий баланс токенов</strong> организации. Под балансом находится <strong>мини-столбчатая диаграмма за последние 14 дней</strong>, где:</p><ul><li><strong>зелёные столбцы</strong> — пополнения (кредиты);</li><li><strong>красные столбцы</strong> — списания за использование (дебеты).</li></ul><p>Диаграмма позволяет быстро оценить динамику расходования средств.</p><h3 id="текущии-тариф" tabindex="-1">Текущий тариф <a class="header-anchor" href="#текущии-тариф" aria-label="Permalink to &quot;Текущий тариф&quot;">​</a></h3><p>Рядом с балансом отображается карточка <strong>активного тарифного плана</strong>:</p><table tabindex="0"><thead><tr><th>Параметр</th><th>Описание</th></tr></thead><tbody><tr><td><strong>Цена за 1M токенов</strong></td><td>Стоимость одного миллиона входных токенов</td></tr><tr><td><strong>Множитель выхода</strong></td><td>Коэффициент, на который умножается цена для выходных токенов (output обычно дороже input)</td></tr><tr><td><strong>Валюта</strong></td><td>Валюта расчёта — <strong>RUB</strong> или <strong>USD</strong></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Выбор валюты</p><p>Валюта организации определяется <strong>при её создании</strong> на основе выбранного языка интерфейса и не может быть изменена позже.</p></div><h3 id="пополнение-баланса" tabindex="-1">Пополнение баланса <a class="header-anchor" href="#пополнение-баланса" aria-label="Permalink to &quot;Пополнение баланса&quot;">​</a></h3><ol><li>Нажмите кнопку <strong>«Пополнить»</strong> рядом с балансом.</li><li>В модальном окне введите <strong>количество токенов</strong> для пополнения. <ul><li>Минимум: <strong>100 000 токенов</strong></li><li>Максимум: <strong>100 000 000 токенов</strong></li></ul></li><li>Система автоматически рассчитает <strong>ориентировочную стоимость</strong> в валюте вашей организации.</li><li>Нажмите <strong>«Оплатить»</strong> — вы будете перенаправлены на платёжный шлюз.</li></ol><p>После успешной оплаты баланс обновится автоматически.</p><h3 id="история-транзакции" tabindex="-1">История транзакций <a class="header-anchor" href="#история-транзакции" aria-label="Permalink to &quot;История транзакций&quot;">​</a></h3><p>В нижней части страницы находится таблица всех операций с балансом с возможностью фильтрации:</p><table tabindex="0"><thead><tr><th>Фильтр</th><th>Описание</th></tr></thead><tbody><tr><td><strong>Тип транзакции</strong></td><td>Фильтр по категории (см. ниже)</td></tr><tr><td><strong>Диапазон дат</strong></td><td>Фильтр по дате совершения операции</td></tr></tbody></table><h4 id="типы-транзакции" tabindex="-1">Типы транзакций <a class="header-anchor" href="#типы-транзакции" aria-label="Permalink to &quot;Типы транзакций&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Тип</th><th>Описание</th></tr></thead><tbody><tr><td><strong>Usage</strong></td><td>Списание за анализ инцидента или уточняющий вопрос</td></tr><tr><td><strong>Top-up</strong></td><td>Пополнение баланса через платёжный шлюз</td></tr><tr><td><strong>Gift</strong></td><td>Подарочные токены, начисленные администратором</td></tr><tr><td><strong>Refund</strong></td><td>Возврат средств (например, при ошибочном списании)</td></tr></tbody></table><p>Транзакции типа <strong>Usage</strong> содержат ссылку на связанный инцидент — нажмите на неё, чтобы перейти к детальной карточке и посмотреть, за что именно были списаны токены.</p><h3 id="защита-от-отрицательного-баланса" tabindex="-1">Защита от отрицательного баланса <a class="header-anchor" href="#защита-от-отрицательного-баланса" aria-label="Permalink to &quot;Защита от отрицательного баланса&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Блокировка анализа</p><p>Если баланс падает <strong>ниже нуля</strong>, SREBot <strong>прекращает анализ новых оповещений</strong>. Вместо этого в чат (Telegram/Slack/Discord) приходит уведомление о необходимости пополнить баланс. Анализ возобновляется автоматически после пополнения.</p></div><hr><h2 id="аккаунт-и-безопасность-dashboard-settings" tabindex="-1">Аккаунт и безопасность (<code>/dashboard/settings</code>) <a class="header-anchor" href="#аккаунт-и-безопасность-dashboard-settings" aria-label="Permalink to &quot;Аккаунт и безопасность (`/dashboard/settings`)&quot;">​</a></h2><p>На странице настроек вы управляете параметрами своего профиля и контекстом организации.</p><h3 id="смена-пароля" tabindex="-1">Смена пароля <a class="header-anchor" href="#смена-пароля" aria-label="Permalink to &quot;Смена пароля&quot;">​</a></h3><p>Для смены пароля:</p><ol><li>Введите текущий пароль в поле <strong>«Текущий пароль»</strong>.</li><li>Введите новый пароль в поле <strong>«Новый пароль»</strong> (минимум 8 символов).</li><li>Подтвердите новый пароль в поле <strong>«Подтвердите пароль»</strong>.</li><li>Нажмите <strong>«Сохранить»</strong>.</li></ol><h3 id="контекст-организации" tabindex="-1">Контекст организации <a class="header-anchor" href="#контекст-организации" aria-label="Permalink to &quot;Контекст организации&quot;">​</a></h3><p>На странице настроек отображается информация о текущей организации:</p><ul><li><strong>Название организации</strong></li><li><strong>Ваша роль</strong> в этой организации (Owner / Admin / Member / Viewer)</li></ul><p>Для управления участниками организации перейдите в раздел <strong>«Команда»</strong> (доступно только для Владельцев и Администраторов). Подробнее об этом читайте в разделе <a href="/docs/guide/team-management">Управление командой</a>.</p>',97)])])}const p=r(e,[["render",s]]);export{b as __pageData,p as default};
